-- Authors
INSERT INTO authors (id, name, bio, birth_date, death_date, photo_url) VALUES
('22222222-0000-0000-0000-000000000001', 'Абай Құнанбайұлы',
 'Великий казахский поэт, философ, просветитель и основоположник казахской письменной литературы. Автор сборника философско-дидактических эссе «Қара сөздер» (Слова назидания) и множества лирических стихотворений. Абай внёс огромный вклад в духовное развитие казахского народа, сумев объединить культуры Востока и Запада. Его произведения демонстрируют богатство и красоту казахского языка и по сей день остаются нравственным ориентиром для казахстанцев.',
 '1845-08-10', '1904-07-06',
 'https://api.oqyrman.app/minio/oqyrman/authors/abay.jpg'),

('22222222-0000-0000-0000-000000000002', 'Мұхтар Әуезов',
 'Выдающийся казахский писатель, драматург, учёный и общественный деятель. Автор роман-эпопеи «Абай жолы» (Путь Абая) — вершины казахской литературы. Академик АН КазССР, народный писатель Казахстана. Автор сотен повестей, пьес и научных трудов. Произведения Мухтара Ауэзова переведены на многие языки мира и признаны мировым литературным наследием.',
 '1897-09-28', '1961-06-27',
 'https://api.oqyrman.app/minio/oqyrman/authors/auezov.jpg'),

('22222222-0000-0000-0000-000000000003', 'Ілияс Есенберлин',
 'Выдающийся казахский исторический романист, автор трилогии «Кочевники» (Көшпенділер). Это произведение описывает образование Казахского ханства и борьбу казахского народа за независимость в XV–XVIII веках. Также автор романов «Золотая Орда» и «Отчаяние». Есенберлин внёс особый вклад в развитие казахской исторической прозы и сохранение памяти о великом прошлом степного народа.',
 '1915-01-24', '1983-07-10',
 'https://api.oqyrman.app/minio/oqyrman/authors/esenberlin.jpeg'),

('22222222-0000-0000-0000-000000000004', 'Ғабит Мүсірепов',
 'Крупнейший казахский писатель и драматург, народный писатель Казахской ССР. Автор романа «Улпан» и повести «Солдат из Казахстана». Мусрепов глубоко раскрыл в казахской литературе темы женской судьбы, нравственности и героизма. Многие его пьесы ставились на сценах казахских театров и вошли в золотой фонд национальной драматургии.',
 '1902-03-09', '1985-12-21',
 'https://api.oqyrman.app/minio/oqyrman/authors/musrepov.jpg'),

('22222222-0000-0000-0000-000000000005', 'Сәкен Сейфуллин',
 'Казахский поэт, прозаик, государственный деятель и один из основоположников казахской советской литературы. Автор автобиографического романа «Тар жол, тайғақ кешу» (Тернистый путь) и поэмы «Экспресс». Сейфуллин внёс огромный вклад в развитие казахского литературного языка, написал ряд учебников и статей. Стал жертвой политических репрессий и был расстрелян в 1938 году.',
 '1894-10-15', '1938-04-25',
 'https://api.oqyrman.app/minio/oqyrman/authors/seifullin.jpg'),

('22222222-0000-0000-0000-000000000006', 'Мағжан Жұмабаев',
 'Один из крупнейших казахских поэтов XX века, педагог, переводчик и общественный деятель. Его лирика отличается философской глубиной, искренностью в теме любви и Родины. Поэма «Батыр Баян» является жемчужиной казахской поэзии. Магжан Жумабаев стал жертвой репрессий 1938 года и был реабилитирован посмертно.',
 '1893-06-25', '1938-03-19',
 'https://api.oqyrman.app/minio/oqyrman/authors/jumabayev.jpg'),

('22222222-0000-0000-0000-000000000007', 'Бейімбет Майлин',
 'Один из основоположников казахской советской литературы — писатель, поэт и драматург. Его произведения правдиво описывают быт казахского аула, социальные перемены и человеческие судьбы. Автор множества рассказов и повестей, среди которых «Азамат Азаматыч» и «Шуганын белгиси». Стал жертвой политических репрессий в 1938 году.',
 '1894-11-18', '1938-04-10',
 'https://api.oqyrman.app/minio/oqyrman/authors/mailin.jpg'),

('22222222-0000-0000-0000-000000000031', 'Шәкәрім Құдайбердіұлы',
 'Выдающийся казахский поэт, философ, историк и композитор, племянник Абая Кунанбаева. Автор философско-этического трактата «Үш анық» (Три истины) и исторического труда «Қазақ айнасы» (Зеркало казахов). Его поэзия отличается глубоким философским содержанием и нравственными исканиями. Был расстрелян в 1931 году, реабилитирован посмертно.',
 '1858-07-11', '1931-10-02',
 'https://api.oqyrman.app/minio/oqyrman/authors/qudaiberdi.jpg'),

('22222222-0000-0000-0000-000000000032', 'Жүсіпбек Аймауытов',
 'Казахский писатель, драматург, педагог и общественный деятель начала XX века. Автор первых психологических романов в казахской литературе — «Қартқожа» и «Ақбілек». Внёс значительный вклад в развитие казахской педагогики, музыковедения и литературной критики. Стал жертвой репрессий и был расстрелян в 1929 году.',
 '1889-09-12', '1931-04-02',
 'https://api.oqyrman.app/minio/oqyrman/authors/aimauytov.jpg'),

('22222222-0000-0000-0000-000000000033', 'Мұқағали Мақатаев',
 'Выдающийся казахский поэт второй половины XX века, один из самых любимых поэтов Казахстана. Автор поэтических сборников «Аққулар ұйықтағанда» (Когда лебеди спят), «Мавр» и «Шуақ». Его стихи пронизаны любовью к родной земле, тонким лиризмом и философскими размышлениями о жизни. Удостоен Государственной премии Казахстана посмертно.',
 '1931-02-09', '1976-03-27',
 'https://api.oqyrman.app/minio/oqyrman/authors/maqatayev.jpg'),

('22222222-0000-0000-0000-000000000034', 'Қасым Аманжолов',
 'Крупный казахский поэт, один из ярчайших лириков XX века. Автор поэм «Ақын өлімі туралы аңыз» (Легенда о смерти поэта) и множества стихотворений о любви, войне и Родине. Его фронтовая лирика периода Великой Отечественной войны считается вершиной казахской военной поэзии. Творчество Аманжолова оказало огромное влияние на последующие поколения казахских поэтов.',
 '1911-01-20', '1955-01-06',
 'https://api.oqyrman.app/minio/oqyrman/authors/amanzholov.jpg'),

('22222222-0000-0000-0000-000000000035', 'Олжас Сүлейменов',
 'Выдающийся казахский поэт, писатель, общественный и политический деятель, дипломат. Автор знаменитой книги «Аз и Я», ставшей литературным и научным событием. Его стихи отличаются новаторством, космическими образами и глубоким историческим осмыслением. Был депутатом Верховного Совета, возглавлял антиядерное движение «Невада — Семипалатинск».',
 '1936-05-18', NULL,
 'https://api.oqyrman.app/minio/oqyrman/authors/suleimenov.jpg'),

('22222222-0000-0000-0000-000000000036', 'Жамбыл Жабаев',
 'Великий казахский народный поэт-акын и импровизатор, один из последних представителей устной поэтической традиции. Прославился мастерством айтыса — поэтических состязаний. Его стихи и песни посвящены казахской степи, народному быту и героическому прошлому. Жамбыл дожил до глубокой старости и стал символом преемственности казахской устной поэзии.',
 '1846-02-28', '1945-06-22',
 'https://api.oqyrman.app/minio/oqyrman/authors/zhabayev.jpg'),

('22222222-0000-0000-0000-000000000037', 'Бауыржан Момышұлы',
 'Казахский военный писатель, Герой Советского Союза, панфиловец. Автор автобиографической повести «Москва үшін шайқас» (За нами Москва) о битве за Москву 1941 года. Его произведения являются образцом военной прозы, основанной на личном боевом опыте. Командовал батальоном в составе легендарной 316-й стрелковой дивизии генерала Панфилова.',
 '1910-12-24', '1982-06-10',
 'https://api.oqyrman.app/minio/oqyrman/authors/momyshuly.jpg'),

('22222222-0000-0000-0000-000000000038', 'Дулат Бабатайұлы',
 'Казахский поэт XIX века, один из представителей эпохи «Зар заман» (Эпоха скорби). Его стихи проникнуты тревогой за судьбу казахского народа в условиях колониализма. Автор поэмы «Осиет-нама» (Книга завещаний), в которой призывал народ к просвещению и сохранению национальной идентичности. Творчество Дулата оказало влияние на формирование казахского национального самосознания.',
 '1802-01-01', '1871-01-01',
 'https://api.oqyrman.app/minio/oqyrman/authors/babatayuly.jpg'),

('22222222-0000-0000-0000-000000000039', 'Мұхтар Шаханов',
 'Известный казахский поэт, общественный и политический деятель. Автор поэм «Отырардың күйреуі» (Гибель Отрара), «Нарындағы наз», множества стихотворений и книг-диалогов с Чингизом Айтматовым. Его творчество посвящено казахской истории, экологии и нравственным проблемам современности. Был депутатом Верховного Совета, активно боролся за прекращение ядерных испытаний.',
 '1942-08-22', NULL,
 'https://api.oqyrman.app/minio/oqyrman/authors/shakhanov.jpg'),

('22222222-0000-0000-0000-000000000040', 'Міржақып Дулатов',
 'Казахский поэт, писатель, журналист и общественный деятель, один из лидеров движения «Алаш». Автор первого казахского романа «Бақытсыз Жамал» (Несчастная Жамал, 1910) и поэтического сборника «Оян, қазақ!» (Проснись, казах!). Его произведения призывали народ к просвещению и национальному самосознанию. Стал жертвой репрессий и был расстрелян в 1935 году.',
 '1885-11-25', '1935-10-05',
 'https://api.oqyrman.app/minio/oqyrman/authors/dulatov.jpg'),

('22222222-0000-0000-0000-000000000008', 'Лев Толстой',
 'Русский писатель, один из величайших романистов в истории мировой литературы. Автор монументальных романов «Война и мир» и «Анна Каренина», признанных вершинами реалистической прозы. Толстой также был философом, моралистом и общественным деятелем. Его идеи ненасилия оказали влияние на Махатму Ганди и Мартина Лютера Кинга. Последние годы жизни посвятил духовным исканиям и созданию собственного учения.',
 '1828-09-09', '1910-11-20',
 'https://api.oqyrman.app/minio/oqyrman/authors/tolstoy.jpg'),

('22222222-0000-0000-0000-000000000009', 'Фёдор Достоевский',
 'Русский писатель, мыслитель и философ, один из самых значимых авторов мировой литературы. Его романы «Преступление и наказание», «Идиот», «Бесы» и «Братья Карамазовы» стали основой психологического романа. Достоевский глубоко исследовал человеческую душу, проблемы свободы, веры и нравственного выбора. Пережил каторгу и ссылку, что нашло отражение в его творчестве.',
 '1821-11-11', '1881-02-09',
 'https://api.oqyrman.app/minio/oqyrman/authors/dostayevskiy.jpg'),

('22222222-0000-0000-0000-000000000010', 'Антон Чехов',
 'Русский писатель и драматург, признанный одним из величайших мастеров короткого рассказа в мировой литературе. Его пьесы «Вишнёвый сад», «Три сестры», «Чайка» и «Дядя Ваня» стали классикой мирового театра. Чехов был также врачом и общественным деятелем, совершил путешествие на Сахалин. Его проза отличается тонким психологизмом и лиризмом.',
 '1860-01-29', '1904-07-15',
 'https://api.oqyrman.app/minio/oqyrman/authors/chehov.jpg'),

('22222222-0000-0000-0000-000000000011', 'Михаил Булгаков',
 'Русский писатель и драматург, автор знаменитого романа «Мастер и Маргарита» — одного из самых читаемых произведений XX века. Также написал «Белую гвардию», «Собачье сердце», «Роковые яйца» и пьесы для МХАТа. Булгаков мастерски соединял сатиру, фантастику и глубокий психологизм. При жизни многие его произведения были запрещены к публикации.',
 '1891-05-15', '1940-03-10',
 'https://api.oqyrman.app/minio/oqyrman/authors/bulgakov.jpg'),

('22222222-0000-0000-0000-000000000012', 'Александр Пушкин',
 'Великий русский поэт, основоположник современного русского литературного языка. Автор романа в стихах «Евгений Онегин», поэм «Медный всадник» и «Руслан и Людмила», повести «Капитанская дочка», «Пиковая дамы» и множества стихотворений. Пушкин заложил основы русской реалистической литературы и оказал огромное влияние на всю русскую культуру. Погиб на дуэли в возрасте 37 лет.',
 '1799-06-06', '1837-02-10',
 'https://api.oqyrman.app/minio/oqyrman/authors/pushkin.jpg'),

('22222222-0000-0000-0000-000000000013', 'Николай Гоголь',
 'Русский прозаик и драматург, классик мировой литературы. Автор поэмы «Мёртвые души», комедии «Ревизор», повестей «Тарас Бульба», «Шинель» и «Нос». Гоголь создал неповторимый художественный мир, сочетающий реализм, гротеск и мистику. Его сатира на российскую бюрократию и нравы общества остаётся актуальной по сей день.',
 '1809-04-01', '1852-03-04',
 'https://api.oqyrman.app/minio/oqyrman/authors/gogol.jpg'),

('22222222-0000-0000-0000-000000000014', 'Иван Тургенев',
 'Русский писатель и поэт, один из крупнейших представителей русского реализма. Автор романов «Отцы и дети», «Дворянское гнездо», «Накануне» и повести «Муму». Тургенев первым из русских писателей получил широкое признание в Европе. Его произведения отличаются поэтичностью языка и глубоким психологизмом в изображении человеческих чувств.',
 '1818-11-09', '1883-09-03',
 'https://api.oqyrman.app/minio/oqyrman/authors/turgenev.jpg'),

('22222222-0000-0000-0000-000000000015', 'Эрнест Хемингуэй',
 'Американский писатель и журналист, лауреат Нобелевской премии по литературе 1954 года. Автор романов «Старик и море», «По ком звонит колокол», «Прощай, оружие!» и «Фиеста». Хемингуэй создал уникальный лаконичный стиль, оказавший огромное влияние на литературу XX века. Участвовал в двух мировых войнах и Гражданской войне в Испании.',
 '1899-07-21', '1961-07-02',
 'https://api.oqyrman.app/minio/oqyrman/authors/hemingway.jpg'),

('22222222-0000-0000-0000-000000000016', 'Франц Кафка',
 'Немецкоязычный писатель из Праги, один из крупнейших прозаиков XX века. Автор романов «Процесс», «Замок» и новеллы «Превращение». Его произведения проникнуты чувством абсурда, одиночества и бессилия человека перед бюрократической машиной. Кафка оказал глубочайшее влияние на мировую литературу, породив понятие «кафкианский».',
 '1883-07-03', '1924-06-03',
 'https://api.oqyrman.app/minio/oqyrman/authors/kafka.jpg'),

('22222222-0000-0000-0000-000000000017', 'Альбер Камю',
 'Французский писатель, философ и публицист, лауреат Нобелевской премии по литературе 1957 года. Автор романов «Посторонний» и «Чума», философского эссе «Миф о Сизифе». Камю — один из основоположников философии абсурдизма и экзистенциализма. Родился в Алжире, активно участвовал в движении Сопротивления во время Второй мировой войны. Погиб в автокатастрофе в возрасте 46 лет.',
 '1913-11-07', '1960-01-04',
 'https://api.oqyrman.app/minio/oqyrman/authors/kamu.jpg'),

('22222222-0000-0000-0000-000000000018', 'Габриэль Гарсиа Маркес',
 'Колумбийский писатель и журналист, лауреат Нобелевской премии по литературе 1982 года. Автор романа «Сто лет одиночества» — вершины магического реализма, а также «Любовь во время чумы» и «Осень патриарха». Маркес соединял мифологию и реальность Латинской Америки, создавая неповторимый литературный мир. Его произведения переведены на десятки языков мира.',
 '1927-03-06', '2014-04-17',
 'https://api.oqyrman.app/minio/oqyrman/authors/Gabriel_Garcia_Marquez.jpg'),

('22222222-0000-0000-0000-000000000019', 'Джордж Оруэлл',
 'Английский писатель и публицист, автор знаменитых антиутопий «1984» и «Скотный двор». Настоящее имя — Эрик Артур Блэр. Оруэлл создал пророческие произведения о тоталитаризме, цензуре и манипуляции сознанием, которые остаются актуальными в XXI веке. Участвовал в Гражданской войне в Испании, был ранен. Его эссеистика считается образцом английской прозы.',
 '1903-06-25', '1950-01-21',
 'https://api.oqyrman.app/minio/oqyrman/authors/orwell.jpg'),

('22222222-0000-0000-0000-000000000020', 'Харуки Мураками',
 'Японский писатель и переводчик, один из наиболее читаемых и влиятельных современных авторов мира. Автор романов «Норвежский лес», «Кафка на пляже», «1Q84» и «Охота на овец». Мураками создал уникальный стиль, сочетающий западную поп-культуру, японскую эстетику и сюрреализм. Его произведения переведены более чем на 50 языков.',
 '1949-01-12', NULL,
 'https://api.oqyrman.app/minio/oqyrman/authors/murakami.webp'),

('22222222-0000-0000-0000-000000000021', 'Агата Кристи',
 'Английская писательница, королева детективного жанра. Автор более 60 детективных романов, включая серии об Эркюле Пуаро и мисс Марпл. Её книги «Убийство в Восточном экспрессе», «Десять негритят» и «Убийство Роджера Экройда» стали классикой мирового детектива. Агата Кристи — самый продаваемый автор художественной литературы всех времён, её книги разошлись тиражом более 2 миллиардов экземпляров.',
 '1890-09-15', '1976-01-12',
 'https://api.oqyrman.app/minio/oqyrman/authors/kristi.jpg'),

('22222222-0000-0000-0000-000000000022', 'Артур Конан Дойл',
 'Английский писатель и врач, создатель легендарного сыщика Шерлока Холмса и его верного друга доктора Ватсона. Написал четыре романа и 56 рассказов о Холмсе, которые стали эталоном детективного жанра. Конан Дойл также автор исторических романов, научной фантастики и приключенческой прозы. Был рыцарем Британской империи.',
 '1859-05-22', '1930-07-07',
 'https://api.oqyrman.app/minio/oqyrman/authors/doil.png'),

('22222222-0000-0000-0000-000000000023', 'Виктор Гюго',
 'Французский поэт, прозаик и драматург, один из главных представителей романтизма. Автор романов «Отверженные» и «Собор Парижской Богоматери», признанных шедеврами мировой литературы. Гюго был также политическим деятелем — депутатом и сенатором Франции. Его творчество пронизано идеями справедливости, милосердия и борьбы за права человека.',
 '1802-02-26', '1885-05-22',
 'https://api.oqyrman.app/minio/oqyrman/authors/gugo.jpg'),

('22222222-0000-0000-0000-000000000024', 'Жюль Верн',
 'Французский писатель, один из основоположников жанра научной фантастики. Автор более 60 романов, включая «Двадцать тысяч лье под водой», «Вокруг света за 80 дней», «Путешествие к центру Земли» и «Таинственный остров». Многие из его предсказаний — подводные лодки, космические полёты, вертолёты — впоследствии стали реальностью. Верн является одним из самых переводимых авторов в истории.',
 '1828-02-08', '1905-03-24',
 'https://api.oqyrman.app/minio/oqyrman/authors/verne.jpg'),

('22222222-0000-0000-0000-000000000025', 'Александр Дюма',
 'Французский писатель, классик приключенческого жанра. Автор всемирно известных романов «Три мушкетёра», «Граф Монте-Кристо» и «Двадцать лет спустя». Дюма написал более 250 произведений, его романы переведены почти на все языки мира. Его герои — д''Артаньян, Атос, Портос и Арамис — стали символами дружбы, чести и отваги.',
 '1802-07-24', '1870-12-05',
 'https://api.oqyrman.app/minio/oqyrman/authors/duma.jpg'),

('22222222-0000-0000-0000-000000000026', 'Стивен Кинг',
 'Американский писатель, работающий в жанрах ужасов, триллера, мистики и фантастики. Автор более 60 романов, включая «Зелёную милю», «Оно», «Сияние» и «Мизери». Его произведения многократно экранизированы и стали основой для десятков фильмов и сериалов. Кинг считается «королём ужасов» и одним из самых коммерчески успешных писателей в истории.',
 '1947-09-21', NULL,
 'https://api.oqyrman.app/minio/oqyrman/authors/king.jpg'),

('22222222-0000-0000-0000-000000000027', 'Джек Лондон',
 'Американский писатель и журналист, мастер приключенческой прозы. Автор романов «Зов предков», «Белый Клык», «Мартин Иден» и «Морской волк». Его произведения пронизаны темой борьбы человека с природой и обществом. Лондон прожил яркую, но короткую жизнь — был золотоискателем на Клондайке, моряком и военным корреспондентом.',
 '1876-01-12', '1916-11-22',
 'https://api.oqyrman.app/minio/oqyrman/authors/london.jpg'),

('22222222-0000-0000-0000-000000000028', 'Чарльз Диккенс',
 'Английский писатель, величайший романист Викторианской эпохи. Автор романов «Оливер Твист», «Большие надежды», «Дэвид Копперфилд», «Повесть о двух городах» и «Рождественская история». Диккенс создавал яркие, незабываемые образы и остро критиковал социальную несправедливость своего времени. Его произведения оказали огромное влияние на развитие английского реализма.',
 '1812-02-07', '1870-06-09',
 'https://api.oqyrman.app/minio/oqyrman/authors/dickkens.jpg'),

('22222222-0000-0000-0000-000000000029', 'Марк Твен',
 'Американский писатель, журналист и общественный деятель, настоящее имя — Сэмюэл Клеменс. Автор романов «Приключения Тома Сойера» и «Приключения Гекльберри Финна», ставших классикой мировой литературы. Мастер сатиры и юмора, Твен считается отцом американской литературы. Уильям Фолкнер называл его «первым подлинно американским писателем».',
 '1835-11-30', '1910-04-21',
 'https://api.oqyrman.app/minio/oqyrman/authors/twain.jpg'),

('22222222-0000-0000-0000-000000000030', 'Айзек Азимов',
 'Американский писатель-фантаст и популяризатор науки, один из «Большой тройки» научной фантастики наряду с Артуром Кларком и Робертом Хайнлайном. Автор серии «Основание», цикла о роботах и более 500 книг на самые разные темы. Азимов сформулировал знаменитые «Три закона робототехники», ставшие частью мировой культуры. Его произведения предвосхитили многие технологические разработки.',
 '1920-01-02', '1992-04-06',
 'https://api.oqyrman.app/minio/oqyrman/authors/azimov.jpg')
