INSERT INTO events (id, title, description, cover_url, location, starts_at, ends_at) VALUES

('77777777-0000-0000-0000-000000000001',
 'Абай оқулары — Чтения Абая',
 'Ежегодные чтения поэзии Абая Кунанбаева. Выступления чтецов, музыкальное сопровождение домбристов, обсуждение философских идей великого поэта.',
 'https://api.oqyrman.app/minio/oqyrman/events/001.jpg',
 'Национальная библиотека Республики Казахстан, конференц-зал',
 '2026-04-23 11:00:00+06', '2026-04-23 15:00:00+06'),

('77777777-0000-0000-0000-000000000002',
 'Книжный клуб: Мастер и Маргарита',
 'Обсуждение романа Михаила Булгакова. Разбираем символику, исторический контекст и вечные темы добра и зла.',
 'https://api.oqyrman.app/minio/oqyrman/events/002.jpg',
 'Библиотека им. Мухтара Ауэзова, читальный зал',
 '2026-04-26 18:00:00+06', '2026-04-26 20:00:00+06'),

('77777777-0000-0000-0000-000000000003',
 'Лекция: Казахская литература XX века',
 'Обзор ключевых произведений и авторов казахской литературы советского периода. Ауэзов, Есенберлин, Мусрепов — судьбы и творчество.',
 'https://api.oqyrman.app/minio/oqyrman/events/003.jpg',
 'Библиотека им. Аль-Фараби (КазНУ), ауд. 310',
 '2026-05-05 10:00:00+06', '2026-05-05 12:00:00+06'),

('77777777-0000-0000-0000-000000000004',
 'Детский читательский марафон',
 'Соревнование по чтению для детей 7–12 лет. Конкурсы, викторины по книгам, призы и дипломы участникам.',
 'https://api.oqyrman.app/minio/oqyrman/events/004.jpg',
 'Городская детская библиотека им. И.А. Крылова',
 '2026-05-01 10:00:00+06', '2026-05-01 14:00:00+06'),

('77777777-0000-0000-0000-000000000005',
 'Встреча с современными казахскими писателями',
 'Живая встреча с авторами современной казахской прозы и поэзии. Автограф-сессия, обсуждение новых книг, творческий вечер.',
 'https://api.oqyrman.app/minio/oqyrman/events/005.jpg',
 'Центральная городская библиотека им. А.П. Чехова, актовый зал',
 '2026-05-15 17:00:00+06', '2026-05-15 20:00:00+06'),

('77777777-0000-0000-0000-000000000006',
 'Мировая фантастика: от Верна до Азимова',
 'Лекция о классиках научной фантастики. История жанра, ключевые произведения, влияние на науку и технологии.',
 'https://api.oqyrman.app/minio/oqyrman/events/006.jpg',
 'Республиканская научно-техническая библиотека, конференц-зал',
 '2026-05-20 14:00:00+06', '2026-05-20 16:00:00+06'),

('77777777-0000-0000-0000-000000000007',
 'Вечер поэзии: Серебряный век',
 'Чтения стихотворений Пушкина, Тютчева, Блока, Ахматовой. Музыкальное сопровождение, живая атмосфера литературного салона.',
 'https://api.oqyrman.app/minio/oqyrman/events/007.jpg',
 'Городская юношеская библиотека им. Жамбыла',
 '2026-05-25 19:00:00+06', '2026-05-25 21:00:00+06'),

('77777777-0000-0000-0000-000000000008',
 'Мастер-класс: Как писать рецензию на книгу',
 'Практический мастер-класс для школьников и студентов. Учимся анализировать, структурировать мысли и грамотно излагать впечатления о книге.',
 'https://api.oqyrman.app/minio/oqyrman/events/008.jpg',
 'Библиотека КазНПУ им. Абая',
 '2026-06-01 11:00:00+06', '2026-06-01 13:00:00+06'),

('77777777-0000-0000-0000-000000000009',
 'Книжная ярмарка Алматы',
 'Ежегодная книжная ярмарка. Более 50 издательств, презентации новинок, скидки, встречи с авторами. Вход свободный.',
 'https://api.oqyrman.app/minio/oqyrman/events/009.jpg',
 'КЦДС Атакент, павильон 7',
 '2026-06-10 10:00:00+06', '2026-06-12 19:00:00+06'),

('77777777-0000-0000-0000-000000000010',
 'Философский клуб: Камю и абсурд',
 'Разбираем философию Альбера Камю — Посторонний, Миф о Сизифе, Чума. Что такое абсурд и как с ним жить.',
 'https://api.oqyrman.app/minio/oqyrman/events/010.jpg',
 'Ғылым Ордасы',
 '2026-06-18 18:00:00+06', '2026-06-18 20:30:00+06')

ON CONFLICT (id) DO NOTHING;


INSERT INTO reviews (user_id, book_id, rating, body) VALUES

('66666666-0000-0000-0000-000000000012', '33333333-0000-0000-0000-000000000003', 5,
 'Путь Абая — это не просто роман, это душа казахского народа. Ауэзов создал монументальное произведение, которое должен прочитать каждый.'),

('66666666-0000-0000-0000-000000000013', '33333333-0000-0000-0000-000000000032', 5,
 'Мастер и Маргарита — книга вне времени. Перечитываю каждый год и каждый раз открываю что-то новое. Булгаков — гений.'),

('66666666-0000-0000-0000-000000000014', '33333333-0000-0000-0000-000000000060', 5,
 '1984 актуален как никогда. Читаешь и думаешь — это же про сегодняшний день. Пугающе точное предвидение Оруэлла.'),

('66666666-0000-0000-0000-000000000015', '33333333-0000-0000-0000-000000000057', 5,
 'Сто лет одиночества изменили моё представление о том, каким может быть роман. Магический реализм в лучшем виде.'),

('66666666-0000-0000-0000-000000000016', '33333333-0000-0000-0000-000000000070', 5,
 'Собака Баскервилей — лучший детектив Конан Дойла. Атмосфера болот и тайны просто невероятная. Классика на все времена.'),

('66666666-0000-0000-0000-000000000012', '33333333-0000-0000-0000-000000000021', 5,
 'Преступление и наказание — тяжёлая но необходимая книга. Достоевский залезает в самые тёмные уголки души.'),

('66666666-0000-0000-0000-000000000013', '33333333-0000-0000-0000-000000000082', 5,
 'Зелёная миля довела до слёз. Кинг умеет писать не только ужасы — это история о человечности и несправедливости.'),

('66666666-0000-0000-0000-000000000014', '33333333-0000-0000-0000-000000000015', 5,
 'Война и мир — колоссальный роман. Толстой описывает войну так, что чувствуешь себя участником событий.'),

('66666666-0000-0000-0000-000000000015', '33333333-0000-0000-0000-000000000079', 5,
 'Граф Монте-Кристо — идеальный роман. Месть, справедливость, любовь. Читал три дня не отрываясь.'),

('66666666-0000-0000-0000-000000000016', '33333333-0000-0000-0000-000000000062', 4,
 'Норвежский лес — очень атмосферная книга. Немного грустная, но именно такой она и должна быть. Мураками умеет передать меланхолию.'),

('66666666-0000-0000-0000-000000000012', '33333333-0000-0000-0000-000000000047', 4,
 'Старик и море — маленькая но глубокая книга. История об упорстве и достоинстве. Прочитал за один вечер.'),

('66666666-0000-0000-0000-000000000013', '33333333-0000-0000-0000-000000000066', 5,
 'Убийство в Восточном экспрессе — блестящий детектив. Концовка просто невероятная, не ожидал такого поворота.'),

('66666666-0000-0000-0000-000000000014', '33333333-0000-0000-0000-000000000001', 5,
 'Слова назидания Абая — это мудрость на все времена. Каждое слово весит как золото. Перечитываю регулярно.'),

('66666666-0000-0000-0000-000000000015', '33333333-0000-0000-0000-000000000036', 5,
 'Евгений Онегин — это музыка в прозе. Пушкин создал что-то невероятное. Русский язык в его лучшем проявлении.'),

('66666666-0000-0000-0000-000000000016', '33333333-0000-0000-0000-000000000033', 4,
 'Собачье сердце — едкая сатира. Булгаков высмеял советский строй так точно, что книгу запрещали десятилетиями.')

ON CONFLICT DO NOTHING;


